<template>\n  <div class=\"generation-container\">\n    <div class=\"page-header\">\n      <h2>🤖 生成题目</h2>\n      <p>基于分析结果自动生成模拟题</p>\n    </div>\n\n    <el-card class=\"config-card\">\n      <template #header>\n        <div class=\"card-header\">\n          <span>生成配置</span>\n        </div>\n      </template>\n\n      <el-form :model=\"config\" label-width=\"120px\">\n        <el-form-item label=\"题目数量\">\n          <el-input-number v-model=\"config.num_questions\" :min=\"10\" :max=\"1000\" :step=\"10\"></el-input-number>\n        </el-form-item>\n        \n        <el-form-item label=\"难度分布\">\n          <div class=\"difficulty-input\">\n            <span>简单</span>\n            <el-slider v-model=\"config.difficulty_distribution.easy\" :min=\"0\" :max=\"1\" :step=\"0.1\" style=\"flex: 1;\"></el-slider>\n            <span>{{ (config.difficulty_distribution.easy * 100).toFixed(0) }}%</span>\n          </div>\n          <div class=\"difficulty-input\">\n            <span>中等</span>\n            <el-slider v-model=\"config.difficulty_distribution.medium\" :min=\"0\" :max=\"1\" :step=\"0.1\" style=\"flex: 1;\"></el-slider>\n            <span>{{ (config.difficulty_distribution.medium * 100).toFixed(0) }}%</span>\n          </div>\n          <div class=\"difficulty-input\">\n            <span>困难</span>\n            <el-slider v-model=\"config.difficulty_distribution.hard\" :min=\"0\" :max=\"1\" :step=\"0.1\" style=\"flex: 1;\"></el-slider>\n            <span>{{ (config.difficulty_distribution.hard * 100).toFixed(0) }}%</span>\n          </div>\n        </el-form-item>\n      </el-form>\n\n      <el-button type=\"success\" :loading=\"generating\" @click=\"handleGenerate\" size=\"large\">\n        {{ generating ? '生成中...' : '🚀 开始生成' }}\n      </el-button>\n    </el-card>\n\n    <el-card v-if=\"generationResult\" class=\"result-card\">\n      <template #header>\n        <div class=\"card-header\">\n          <span>生成结果</span>\n        </div>\n      </template>\n\n      <el-alert title=\"生成成功！\" type=\"success\" :closable=\"false\" style=\"margin-bottom: 20px;\">\n        已生成 <strong>{{ generationResult.questions_count }}</strong> 道题目\n      </el-alert>\n\n      <el-descriptions :column=\"1\" border>\n        <el-descriptions-item label=\"题目数量\">\n          {{ generationResult.questions_count }}\n        </el-descriptions-item>\n        <el-descriptions-item label=\"状态\">\n          <el-tag type=\"success\">{{ generationResult.status }}</el-tag>\n        </el-descriptions-item>\n        <el-descriptions-item label=\"消息\">\n          {{ generationResult.message }}\n        </el-descriptions-item>\n      </el-descriptions>\n\n      <el-button type=\"primary\" @click=\"downloadExams\" style=\"margin-top: 20px;\">\n        📥 下载题目\n      </el-button>\n    </el-card>\n  </div>\n</template>\n\n<script setup>\nimport { ref } from 'vue'\nimport api from '../services/api'\nimport { ElMessage } from 'element-plus'\n\nconst config = ref({\n  num_questions: 100,\n  difficulty_distribution: {\n    easy: 0.3,\n    medium: 0.4,\n    hard: 0.3\n  },\n  question_types: ['常识', '言语', '逻辑', '数学', '资料分析']\n})\n\nconst generating = ref(false)\nconst generationResult = ref(null)\n\nconst handleGenerate = async () => {\n  generating.value = true\n  try {\n    const response = await api.generateQuestions(config.value)\n    generationResult.value = response.data\n    ElMessage.success('题目生成完成！')\n  } catch (error) {\n    ElMessage.error('生成失败：' + error.message)\n  } finally {\n    generating.value = false\n  }\n}\n\nconst downloadExams = async () => {\n  try {\n    const response = await api.getReport('exams')\n    const dataStr = JSON.stringify(response.data.data, null, 2)\n    const dataBlob = new Blob([dataStr], { type: 'application/json' })\n    const url = URL.createObjectURL(dataBlob)\n    const link = document.createElement('a')\n    link.href = url\n    link.download = 'generated_exams.json'\n    link.click()\n    ElMessage.success('下载成功！')\n  } catch (error) {\n    ElMessage.error('下载失败：' + error.message)\n  }\n}\n</script>\n\n<style scoped>\n.generation-container {\n  max-width: 1000px;\n  margin: 0 auto;\n}\n\n.page-header {\n  margin-bottom: 20px;\n}\n\n.page-header h2 {\n  font-size: 28px;\n  margin-bottom: 5px;\n}\n\n.page-header p {\n  color: #999;\n}\n\n.config-card {\n  margin-bottom: 20px;\n}\n\n.result-card {\n  background: white;\n}\n\n.card-header {\n  font-weight: bold;\n  font-size: 16px;\n}\n\n.difficulty-input {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  margin-bottom: 15px;\n}\n\n.difficulty-input span:first-child {\n  min-width: 40px;\n  font-weight: 500;\n}\n\n.difficulty-input span:last-child {\n  min-width: 50px;\n  text-align: right;\n  font-weight: bold;\n}\n</style>\n"
